arguments.prompt:
You are building a Blazor WebAssembly PWA for building inspectors on construction sites. The project is already scaffolded at /tmp/sv-e11e3533b0ac451081f331cd6e79a975/SiteInspector/ with a server project (SiteInspector) and client project (SiteInspector.Client).

## Requirements
- Inspectors fill out safety checklists and add notes at each site visit
- Photos attached to inspection reports
- MUST work offline (construction sites have poor/no cellular)
- Syncs to server when connectivity returns
- Mobile phones and tablets (not desktop)
- Low-latency UI — inspectors tap through checklist items quickly
- No authentication

## Architecture Decisions
- **PWA with service worker** for offline support
- **IndexedDB** (via JS interop) for local data persistence
- **Background sync** when connectivity returns
- All interactive components in `.Client` project
- Server project provides API endpoints for sync
- Mobile-first responsive CSS with large tap targets

## Implementation Plan

### 1. Shared Models (in a new SiteInspector.Shared project or just in .Client)
Put models in `SiteInspector.Client/Models/`:

```csharp
// InspectionModels.cs
namespace SiteInspector.Client.Models;

public class ConstructionSite
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;
}

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteId { get; set; } = "";
    public string SiteName { get; set; } = "";
    public DateTime StartedAt { get; set; } = DateTime.UtcNow;
    public DateTime? CompletedAt { get; set; }
    public string Notes { get; set; } = "";
    public List<ChecklistItem> ChecklistItems { get; set; } = new();
    public List<InspectionPhoto> Photos { get; set; } = new();
    public SyncStatus SyncStatus { get; set; } = SyncStatus.Pending;
}

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Category { get; set; } = "";
    public string Description { get; set; } = "";
    public CheckResult Result { get; set; } = CheckResult.NotInspected;
    public string Notes { get; set; } = "";
    public DateTime? InspectedAt { get; set; }
}

public class InspectionPhoto
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string FileName { get; set; } = "";
    public string DataBase64 { get; set; } = ""; // stored as base64 in IndexedDB
    public string Caption { get; set; } = "";
    public DateTime TakenAt { get; set; } = DateTime.UtcNow;
}

public enum CheckResult
{
    NotInspected,
    Pass,
    Fail,
    NotApplicable
}

public enum SyncStatus
{
    Pending,
    Syncing,
    Synced,
    Error
}
```

### 2. JavaScript for IndexedDB (`SiteInspector.Client/wwwroot/js/indexedDb.js`)

```javascript
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (event) => {
            const database = event.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
            }
        };
        request.onsuccess = (event) => { db = event.target.result; resolve(db); };
        request.onerror = (event) => reject(event.target.error);
    });
}

window.indexedDbStorage = {
    initialize: async function() {
        await openDb();
        return true;
    },

    putItem: async function(storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            store.put(item);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function(storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function(storeName, indexName, value) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const index = store.index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            store.delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    }
};
```

### 3. JS for connectivity detection and photo capture (`SiteInspector.Client/wwwroot/js/app.js`)

```javascript
window.connectivityHelper = {
    isOnline: function() {
        return navigator.onLine;
    },
    registerOnlineHandler: function(dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false));
    }
};

window.photoHelper = {
    triggerFileInput: function(inputId) {
        document.getElementById(inputId).click();
    },
    readFileAsBase64: function(inputId) {
        return new Promise((resolve, reject) => {
            const input = document.getElementById(inputId);
            if (!input.files || input.files.length === 0) { resolve(null); return; }
            const file = input.files[0];
            const reader = new FileReader();
            reader.onload = () => {
                const base64 = reader.result.split(',')[1];
                resolve({ fileName: file.name, dataBase64: base64 });
            };
            reader.onerror = () => reject(reader.error);
            reader.readAsDataURL(file);
        });
    }
};
```

### 4. C# Services in `.Client` project

Create `SiteInspector.Client/Services/`:

**IndexedDbService.cs** - wraps JS interop for IndexedDB:
```csharp
using Microsoft.JSInterop;
using System.Text.Json;

namespace SiteInspector.Client.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        if (!_initialized)
        {
            await _js.InvokeVoidAsync("indexedDbStorage.initialize");
            _initialized = true;
        }
    }

    public async Task PutAsync<T>(string storeName, T item)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", storeName, item);
    }

    public async Task<T?> GetAsync<T>(string storeName, string id)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<T?>("indexedDbStorage.getItem", storeName, id);
    }

    public async Task<List<T>> GetAllAsync<T>(string storeName)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<T>>("indexedDbStorage.getAllItems", storeName) ?? new();
    }

    public async Task<List<T>> GetByIndexAsync<T>(string storeName, string indexName, string value)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<T>>("indexedDbStorage.getItemsByIndex", storeName, indexName, value) ?? new();
    }

    public async Task DeleteAsync(string storeName, string id)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", storeName, id);
    }
}
```

