public class InspectionService
{
    private readonly IndexedDbService _db;

    public InspectionService(IndexedDbService db) => _db = db;

    // Sites
    public Task<List<ConstructionSite>> GetSitesAsync() => _db.GetAllAsync<ConstructionSite>("sites");
    public Task SaveSiteAsync(ConstructionSite site) => _db.PutAsync("sites", site);
    public Task DeleteSiteAsync(string id) => _db.DeleteAsync("sites", id);

    // Inspections
