**SyncService.cs** - handles background sync:
```csharp
using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IAsyncDisposable
{
    private readonly InspectionService _inspectionService;
    private readonly HttpClient _http;
    private readonly ConnectivityService _connectivity;
    private Timer? _syncTimer;

    public event Action<string>? OnSyncStatusChanged;

    public SyncService(InspectionService inspectionService, HttpClient http, ConnectivityService connectivity)
    {
        _inspectionService = inspectionService;
        _http = http;
        _connectivity = connectivity;
        _connectivity.OnConnectivityChanged += HandleConnectivityChanged;
    }

    public void StartPeriodicSync()
    {
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(60));
    }

    private async void HandleConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!_connectivity.IsOnline) return;

        try
        {
            var inspections = await _inspectionService.GetInspectionsAsync();
            var pending = inspections.Where(i => i.SyncStatus == SyncStatus.Pending && i.CompletedAt.HasValue).ToList();

            foreach (var inspection in pending)
            {
                inspection.SyncStatus = SyncStatus.Syncing;
                await _inspectionService.SaveInspectionAsync(inspection);
                OnSyncStatusChanged?.Invoke($"Syncing: {inspection.SiteName}");

                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections/sync", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.SyncStatus = SyncStatus.Synced;
                    }
                    else
                    {
                        inspection.SyncStatus = SyncStatus.Error;
                    }
                }
                catch
                {
                    inspection.SyncStatus = SyncStatus.Pending;
                }

                await _inspectionService.SaveInspectionAsync(inspection);
            }

            OnSyncStatusChanged?.Invoke(pending.Any() ? "Sync complete" : "");
        }
        catch
        {
            OnSyncStatusChanged?.Invoke("Sync failed");
        }
    }

    public async ValueTask DisposeAsync()
    {
        _connectivity.OnConnectivityChanged -= HandleConnectivityChanged;
        if (_syncTimer != null) await _syncTimer.DisposeAsync();
    }
}
```

