public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        if (!_initialized)
        {
            await _js.InvokeVoidAsync("indexedDbStorage.initialize");
            _initialized = true;
        }
    }

    public async Task PutAsync<T>(string storeName, T item)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", storeName, item);
    }

    public async Task<T?> GetAsync<T>(string storeName, string id)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<T?>("indexedDbStorage.getItem", storeName, id);
    }

    public async Task<List<T>> GetAllAsync<T>(string storeName)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<T>>("indexedDbStorage.getAllItems", storeName) ?? new();
    }

    public async Task<List<T>> GetByIndexAsync<T>(string storeName, string indexName, string value)
    {
        await InitializeAsync();
        return await _js.InvokeAsync<List<T>>("indexedDbStorage.getItemsByIndex", storeName, indexName, value) ?? new();
    }

    public async Task DeleteAsync(string storeName, string id)
    {
        await InitializeAsync();
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", storeName, id);
    }
}

