@page "/site/{SiteId}"
@inject InspectionService InspectionService
@inject NavigationManager Nav

<PageTitle>Site Details</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@_site?.Name</h1>
</div>

@if (_site != null)
{
    <button class="btn-primary-lg btn-full" @onclick="StartNewInspection">
        📋 Start New Inspection
    </button>

    <h2 class="section-title">Past Inspections</h2>

    @if (_inspections.Any())
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.StartedAt))
            {
                <div class="inspection-card" @onclick="() => Nav.NavigateTo($&quot;/inspection/{inspection.Id}&quot;)">
                    <div class="inspection-card-header">
                        <span class="inspection-date">@inspection.StartedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</span>
                        <span class="sync-badge @GetSyncClass(inspection.SyncStatus)">@inspection.SyncStatus</span>
                    </div>
                    <div class="inspection-summary">
                        @{
                            var passed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass);
                            var failed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
                            var total = inspection.ChecklistItems.Count;
                        }
                        <span class="stat pass">✓ @passed</span>
                        <span class="stat fail">✗ @failed</span>
                        <span class="stat total">of @total items</span>
                        @if (inspection.Photos.Any())
                        {
                            <span class="stat photos">📷 @inspection.Photos.Count</span>
                        }
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        _site = (await InspectionService.GetSitesAsync()).FirstOrDefault(s => s.Id == SiteId);
        if (_site != null)
        {
            _inspections = await InspectionService.GetInspectionsForSiteAsync(SiteId);
        }
    }

    private async Task StartNewInspection()
    {
        if (_site == null) return;
        var inspection = InspectionService.CreateNewInspection(_site);
        await InspectionService.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private string GetSyncClass(SyncStatus status) => status switch
    {
        SyncStatus.Synced => "synced",
        SyncStatus.Error => "error",
        SyncStatus.Syncing => "syncing",
        _ => "pending"
    };
}

@page "/inspection/{InspectionId}"
@inject InspectionService InspectionService
@inject IJSRuntime JS
@inject NavigationManager Nav

<PageTitle>Inspection</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>Inspection</h1>
    @if (_inspection?.CompletedAt == null)
    {
        <button class="btn-complete" @onclick="CompleteInspection">✓ Complete</button>
    }
</div>

@if (_inspection != null)
{
    <div class="inspection-tabs">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            Checklist
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            Photos (@_inspection.Photos.Count)
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist">
            @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <h3>@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @GetItemClass(item.Result)">
                            <div class="checklist-item-text">
                                <span>@item.Description</span>
                                @if (!string.IsNullOrEmpty(item.Notes))
                                {
                                    <span class="item-note">📝 @item.Notes</span>
                                }
                            </div>
                            <div class="checklist-actions">
                                <button class="btn-check pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)"
                                        disabled="@(_inspection.CompletedAt != null)">✓</button>
                                <button class="btn-check fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)"
                                        disabled="@(_inspection.CompletedAt != null)">✗</button>
                                <button class="btn-check na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NotApplicable)"
                                        disabled="@(_inspection.CompletedAt != null)">N/A</button>
                                <button class="btn-check note" @onclick="() => ToggleItemNote(item)"
                                        disabled="@(_inspection.CompletedAt != null)">📝</button>
                            </div>
                        </div>
                        @if (_editingNoteItemId == item.Id)
                        {
                            <div class="item-note-input">
                                <input @bind="item.Notes" @bind:event="oninput" placeholder="Add note..." class="input-lg" />
                                <button class="btn-secondary-lg" @onclick="() => SaveItemNote(item)">Done</button>
                            </div>
                        }
                    }
                </div>
            }
        </div>

        <div class="checklist-progress">
            @{
                var inspected = _inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotInspected);
                var total = _inspection.ChecklistItems.Count;
            }
            <div class="progress-bar">
                <div class="progress-fill" style="width: @(total > 0 ? (inspected * 100 / total) : 0)%"></div>
            </div>
            <span>@inspected / @total inspected</span>
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-section">
            @if (_inspection.CompletedAt == null)
            {
                <button class="btn-primary-lg btn-full" @onclick="TakePhoto">📷 Add Photo</button>
                <input type="file" id="photoInput" accept="image/*" capture="environment" @onchange="OnPhotoSelected" style="display:none" />
            }

            @if (_inspection.Photos.Any())
            {
                <div class="photo-grid">
                    @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                    {
                        <div class="photo-card">
                            <img src="data:image/jpeg;base64,@photo.DataBase64" alt="@photo.Caption" />
                            @if (!string.IsNullOrEmpty(photo.Caption))
                            {
                                <p class="photo-caption">@photo.Caption</p>
                            }
                            <span class="photo-time">@photo.TakenAt.ToLocalTime().ToString("h:mm tt")</span>
                        </div>
                    }
                </div>
            }
            else
            {
                <div class="empty-state">
                    <p>No photos yet. Tap the button above to capture.</p>
                </div>
            }
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-section">
            <textarea @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveNotes"
                      placeholder="General inspection notes..."
                      class="notes-textarea"
                      disabled="@(_inspection.CompletedAt != null)"></textarea>
        </div>
    }
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string? _editingNoteItemId;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await InspectionService.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        if (_inspection?.CompletedAt != null) return;
        item.Result = result;
        item.InspectedAt = DateTime.UtcNow;
        await InspectionService.SaveInspectionAsync(_inspection!);
    }

    private void ToggleItemNote(ChecklistItem item)
    {
        _editingNoteItemId = _editingNoteItemId == item.Id ? null : item.Id;
    }

    private async Task SaveItemNote(ChecklistItem item)
    {
        _editingNoteItemId = null;
        await InspectionService.SaveInspectionAsync(_inspection!);
    }

    private async Task SaveNotes()
    {
        if (_inspection != null)
            await InspectionService.SaveInspectionAsync(_inspection);
    }

    private async Task TakePhoto()
    {
        await JS.InvokeVoidAsync("photoHelper.triggerFileInput", "photoInput");
    }

    private async Task OnPhotoSelected()
    {
        var result = await JS.InvokeAsync<PhotoResult?>("photoHelper.readFileAsBase64", "photoInput");
        if (result != null && _inspection != null)
        {
            var photo = new InspectionPhoto
            {
                FileName = result.FileName,
                DataBase64 = result.DataBase64
            };
            _inspection.Photos.Add(photo);
            await InspectionService.SaveInspectionAsync(_inspection);
        }
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
