arguments.file_text:
{
  "name": "Site Inspector",
  "short_name": "Inspector",
  "start_url": "/",
  "display": "standalone",
  "background_color": "#1a1a2e",
  "theme_color": "#e94560",
  "orientation": "portrait",
  "icons": [
    {
      "src": "icon-192.png",
      "sizes": "192x192",
      "type": "image/png"
    },
    {
      "src": "icon-512.png",
      "sizes": "512x512",
      "type": "image/png"
    }
  ]
}

const CACHE_NAME = 'site-inspector-v1';
const OFFLINE_URLS = [
  '/',
  '/manifest.json'
];

self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME).then(cache => cache.addAll(OFFLINE_URLS))
  );
  self.skipWaiting();
});

self.addEventListener('activate', event => {
  event.waitUntil(
    caches.keys().then(keys =>
      Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
    )
  );
  self.clients.claim();
});

self.addEventListener('fetch', event => {
  if (event.request.method !== 'GET') return;

  event.respondWith(
    fetch(event.request)
      .then(response => {
        const clone = response.clone();
        caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
        return response;
      })
      .catch(() => caches.match(event.request).then(r => r || caches.match('/')))
  );
});

/* Site Inspector - Mobile-first dark theme */
:root {
    --bg-primary: #1a1a2e;
    --bg-secondary: #16213e;
    --bg-card: #0f3460;
    --accent: #e94560;
    --accent-hover: #ff6b6b;
    --success: #4ecdc4;
    --danger: #ff6b6b;
    --warning: #ffd93d;
    --text-primary: #ffffff;
    --text-secondary: #a8b2d1;
    --text-muted: #6c7a99;
    --border: #233554;
    --radius: 12px;
    --radius-sm: 8px;
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px;
    line-height: 1.5;
    background: var(--bg-primary);
    color: var(--text-primary);
    min-height: 100dvh;
    -webkit-font-smoothing: antialiased;
}

.app-container {
    max-width: 768px;
    margin: 0 auto;
    padding: 0 16px 80px;
    min-height: 100dvh;
}

/* Offline Banner */
.offline-banner {
    position: sticky;
    top: 0;
    z-index: 1000;
    background: var(--warning);
    color: #1a1a2e;
    text-align: center;
    padding: 8px 16px;
    font-weight: 600;
    font-size: 14px;
    margin: 0 -16px;
}

/* Page Header */
.page-header {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 20px 0 16px;
    position: sticky;
    top: 0;
    background: var(--bg-primary);
    z-index: 100;
}

.page-header h1 {
    flex: 1;
    margin: 0;
    font-size: 1.5rem;
    font-weight: 700;
}

/* Buttons */
.btn-primary-lg {
    background: var(--accent);
    color: white;
    border: none;
    border-radius: var(--radius-sm);
    padding: 14px 24px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    min-height: 48px;
    touch-action: manipulation;
    transition: background 0.2s;
}

.btn-primary-lg:hover { background: var(--accent-hover); }
.btn-primary-lg:disabled { opacity: 0.5; cursor: not-allowed; }

.btn-secondary-lg {
    background: var(--bg-card);
    color: var(--text-primary);
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    padding: 14px 24px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    min-height: 48px;
    touch-action: manipulation;
}

.btn-back {
    background: none;
    border: none;
    color: var(--accent);
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    padding: 8px 0;
    min-height: 44px;
    touch-action: manipulation;
}

.btn-complete {
    background: var(--success);
    color: var(--bg-primary);
    border: none;
    border-radius: var(--radius-sm);
    padding: 10px 16px;
    font-size: 0.9rem;
    font-weight: 700;
    cursor: pointer;
    min-height: 44px;
    touch-action: manipulation;
}

.btn-full { width: 100%; margin: 8px 0; }

/* Inputs */
.input-lg {
    width: 100%;
    padding: 14px 16px;
    font-size: 1rem;
    border: 1px solid var(--border);
    border-radius: var(--radius-sm);
    background: var(--bg-secondary);
    color: var(--text-primary);
    min-height: 48px;
    margin-bottom: 12px;
}

.input-lg::placeholder { color: var(--text-muted); }
.input-lg:focus { outline: 2px solid var(--accent); border-color: transparent; }

/* Cards */
.card {
    background: var(--bg-card);
    border-radius: var(--radius);
    padding: 20px;
    margin-bottom: 16px;
}

.add-site-form { margin-top: 12px; }

.form-actions {
    display: flex;
    gap: 12px;
    margin-top: 4px;
}

/* Site List */
.site-list { display: flex; flex-direction: column; gap: 12px; }

.site-card {
    background: var(--bg-card);
    border-radius: var(--radius);
    padding: 20px;
    cursor: pointer;
    transition: transform 0.1s, background 0.2s;
    touch-action: manipulation;
}

.site-card:active { transform: scale(0.98); background: var(--bg-secondary); }

.site-card-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.site-card-header h2 {
    margin: 0;
    font-size: 1.2rem;
    font-weight: 600;
}

.chevron {
    font-size: 1.5rem;
    color: var(--text-muted);
}

.site-address {
    margin: 8px 0 0;
    color: var(--text-secondary);
    font-size: 0.9rem;
}

/* Section Title */
.section-title {
    font-size: 1.1rem;
    color: var(--text-secondary);
    margin: 24px 0 12px;
    font-weight: 600;
}

/* Inspection List */
.inspection-list { display: flex; flex-direction: column; gap: 12px; }

.inspection-card {
    background: var(--bg-card);
    border-radius: var(--radius);
    padding: 16px 20px;
    cursor: pointer;
    touch-action: manipulation;
    transition: transform 0.1s;
}

.inspection-card:active { transform: scale(0.98); }

.inspection-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 8px;
}

.inspection-date {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

.sync-badge {
    font-size: 0.75rem;
    padding: 4px 8px;
    border-radius: 12px;
    font-weight: 600;
    text-transform: uppercase;
}

.sync-badge.synced { background: var(--success); color: var(--bg-primary); }
.sync-badge.error { background: var(--danger); color: white; }
.sync-badge.syncing { background: var(--warning); color: var(--bg-primary); }
.sync-badge.pending { background: var(--border); color: var(--text-secondary); }

.inspection-summary {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
}

.stat {
    font-size: 0.9rem;
    font-weight: 600;
}

.stat.pass { color: var(--success); }
.stat.fail { color: var(--danger); }
.stat.total { color: var(--text-muted); }
.stat.photos { color: var(--text-secondary); }

/* Tabs */
.inspection-tabs {
    display: flex;
    gap: 0;
    margin: 0 -16px 16px;
    border-bottom: 1px solid var(--border);
}

.tab {
    flex: 1;
    background: none;
    border: none;
    color: var(--text-muted);
    font-size: 0.95rem;
    font-weight: 600;
    padding: 14px 8px;
    cursor: pointer;
    border-bottom: 3px solid transparent;
    touch-action: manipulation;
    min-height: 48px;
}

.tab.active {
    color: var(--accent);
    border-bottom-color: var(--accent);
}

/* Checklist */
.checklist { display: flex; flex-direction: column; gap: 16px; }

.checklist-category h3 {
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--accent);
    margin: 0 0 8px;
    padding-top: 8px;
    border-top: 1px solid var(--border);
}

.checklist-category:first-child h3 { border-top: none; padding-top: 0; }

.checklist-item {
    background: var(--bg-secondary);
    border-radius: var(--radius-sm);
    padding: 12px 16px;
    margin-bottom: 8px;
    border-left: 4px solid var(--border);
    transition: border-color 0.2s;
}

.checklist-item.item-pass { border-left-color: var(--success); }
.checklist-item.item-fail { border-left-color: var(--danger); }
.checklist-item.item-na { border-left-color: var(--text-muted); }

.checklist-item-text {
    margin-bottom: 10px;
}

.checklist-item-text span {
    display: block;
    font-size: 0.95rem;
}

.item-note {
    font-size: 0.8rem !important;
    color: var(--text-muted);
    margin-top: 4px;
}

.checklist-actions {
    display: flex;
    gap: 8px;
}

.btn-check {
    min-width: 48px;
    min-height: 48px;
    border: 2px solid var(--border);
    border-radius: var(--radius-sm);
    background: var(--bg-primary);
    color: var(--text-secondary);
    font-size: 1rem;
    font-weight: 700;
    cursor: pointer;
    touch-action: manipulation;
    transition: all 0.15s;
    display: flex;
    align-items: center;
    justify-content: center;
}

.btn-check:disabled { opacity: 0.5; cursor: not-allowed; }

.btn-check.pass.selected {
    background: var(--success);
    border-color: var(--success);
    color: var(--bg-primary);
}

.btn-check.fail.selected {
    background: var(--danger);
    border-color: var(--danger);
    color: white;
}

.btn-check.na.selected {
    background: var(--text-muted);
    border-color: var(--text-muted);
    color: white;
}

.btn-check.pass:not(.selected):active { background: rgba(78, 205, 196, 0.2); }
.btn-check.fail:not(.selected):active { background: rgba(255, 107, 107, 0.2); }

.item-note-input {
    display: flex;
    gap: 8px;
    padding: 8px 16px 12px;
    margin-top: -4px;
}

.item-note-input .input-lg { margin-bottom: 0; flex: 1; }

/* Progress Bar */
.checklist-progress {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: var(--bg-secondary);
    padding: 12px 16px;
    display: flex;
    align-items: center;
    gap: 12px;
    border-top: 1px solid var(--border);
    z-index: 100;
}

.progress-bar {
    flex: 1;
    height: 8px;
    background: var(--border);
    border-radius: 4px;
    overflow: hidden;
}

.progress-fill {
    height: 100%;
    background: var(--success);
    border-radius: 4px;
    transition: width 0.3s ease;
}

.checklist-progress span {
    font-size: 0.85rem;
    color: var(--text-secondary);
    white-space: nowrap;
}

/* Photos */
.photos-section { padding-bottom: 20px; }

.photo-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
    margin-top: 16px;
}

.photo-card {
    background: var(--bg-secondary);
    border-radius: var(--radius-sm);
    overflow: hidden;
}

.photo-card img {
    width: 100%;
    height: 150px;
    object-fit: cover;
}

.photo-caption {
    padding: 8px 12px 0;
    font-size: 0.85rem;
    margin: 0;
    color: var(--text-secondary);
}

.photo-time {
    display: block;
    padding: 4px 12px 8px;
    font-size: 0.75rem;
    color: var(--text-muted);
}

/* Notes */
.notes-section { padding-bottom: 20px; }

.notes-textarea {
    width: 100%;
    min-height: 300px;
    padding: 16px;
    font-size: 1rem;
    line-height: 1.6;
    border: 1px solid var(--border);
    border-radius: var(--radius);
    background: var(--bg-secondary);
    color: var(--text-primary);
    resize: vertical;
    font-family: inherit;
}

.notes-textarea::placeholder { color: var(--text-muted); }
.notes-textarea:focus { outline: 2px solid var(--accent); border-color: transparent; }
.notes-textarea:disabled { opacity: 0.7; }

/* Empty State */
.empty-state {
    text-align: center;
    padding: 48px 24px;
    color: var(--text-muted);
}

.empty-state p { margin: 8px 0; font-size: 1rem; }

/* Not Found Page */
.not-found {
    text-align: center;
    padding: 80px 24px;
}

/* Utilities */
@media (min-width: 600px) {
    .photo-grid {
        grid-template-columns: 1fr 1fr 1fr;
    }
}

{
  "name": "Site Inspector",
  "short_name": "Inspector",
  "start_url": "/",
  "display": "standalone",
  "background_color": "#1a1a2e",
  "theme_color": "#e94560",
  "orientation": "portrait",
  "icons": [
    {
      "src": "icon-192.png",
      "sizes": "192x192",
      "type": "image/png"
    },
    {
      "src": "icon-512.png",
      "sizes": "512x512",
      "type": "image/png"
    }
  ]
}

const CACHE_NAME = 'site-inspector-v1';
const OFFLINE_URLS = [
  '/',
  '/manifest.json'
];

self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME).then(cache => cache.addAll(OFFLINE_URLS))
  );
  self.skipWaiting();
});

self.addEventListener('activate', event => {
  event.waitUntil(
    caches.keys().then(keys =>
      Promise.all(keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k)))
    )
  );
  self.clients.claim();
});

self.addEventListener('fetch', event => {
  if (event.request.method !== 'GET') return;

  event.respondWith(
    fetch(event.request)
      .then(response => {
        const clone = response.clone();
        caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
        return response;
      })
      .catch(() => caches.match(event.request).then(r => r || caches.match('/')))
  );
});

