@if (_sites.Any())
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="site-card" @onclick="() => Nav.NavigateTo($&quot;/site/{site.Id}&quot;)">
