    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        _sites = await InspectionService.GetSitesAsync();
    }

    private void ShowAddSite()
    {
        _showAddForm = true;
        _newSiteName = "";
        _newSiteAddress = "";
    }

